import * as React from 'react';
import {
    Autocomplete,
    Avatar,
    Box,
    Chip,
    CircularProgress,
    Stack,
    TextField,
    Typography,
} from '@mui/material';
import LockIcon from '@mui/icons-material/Lock';
import { ProfileServices } from '@/api/profiles.api';
import { ProfileBasicResult } from '@/types/profile.types';
import { logger } from '@/utils/logger';

export type UserPickerOption = {
    id: string;
    name?: string;
    email?: string;
    roles?: string[];
};

interface UserPickerProps {
    /** All currently-selected entries, including any locked ones. */
    value: UserPickerOption[];
    onChange: (next: UserPickerOption[]) => void;
    label: string;
    helperText?: string;
    placeholder?: string;
    /** Ids that must remain selected and cannot be removed. Rendered as a separate locked chip row. */
    lockedIds?: string[];
    /** Ids excluded from the search dropdown (e.g. already-selected as owners on a managers picker). */
    excludeIds?: string[];
    /** Hide search results that are already selected. Defaults to true. */
    hideAlreadySelected?: boolean;
    disabled?: boolean;
    /** Delay (ms) between keystroke and search request. */
    debounceMs?: number;
    error?: boolean;
    required?: boolean;
}

/**
 * Async people picker restricted to users with elevated roles
 * (EventMgr, SchoolAdmin, BatchAdmin, Admin, SuperAdmin).
 *
 * Backed by `GET /profile/elevated/search` — only callers with EventMgr or higher
 * can use it. Server reads from an in-memory profile index, so per-keystroke
 * searches do not hit Cosmos. Locked entries (e.g. the current user as owner)
 * render as a separate non-removable chip row above the Autocomplete.
 */
export const UserPicker: React.FC<UserPickerProps> = ({
    value,
    onChange,
    label,
    helperText,
    placeholder,
    lockedIds = [],
    excludeIds = [],
    hideAlreadySelected = true,
    disabled = false,
    debounceMs = 250,
    error = false,
    required = false,
}) => {
    const [open, setOpen] = React.useState(false);
    const [inputValue, setInputValue] = React.useState('');
    const [options, setOptions] = React.useState<UserPickerOption[]>([]);
    const [loading, setLoading] = React.useState(false);
    // Bumped on each request; stale responses are ignored.
    const requestIdRef = React.useRef(0);

    const lockedSet = React.useMemo(() => new Set(lockedIds), [lockedIds]);
    const excludeSet = React.useMemo(() => new Set(excludeIds), [excludeIds]);

    // Locked entries are pulled out of the Autocomplete value so MUI's default
    // chip rendering doesn't expose a delete affordance for them.
    const lockedEntries = React.useMemo(
        () => value.filter(v => lockedSet.has(v.id)),
        [value, lockedSet]);
    const editableEntries = React.useMemo(
        () => value.filter(v => !lockedSet.has(v.id)),
        [value, lockedSet]);

    // Debounced fetch: re-runs whenever the dropdown is open and the typed text changes.
    React.useEffect(() => {
        if (!open) return;
        const handle = window.setTimeout(() => {
            const reqId = ++requestIdRef.current;
            setLoading(true);
            ProfileServices.SearchElevatedProfiles(inputValue, 20)
                .then(res => {
                    if (reqId !== requestIdRef.current) return; // stale
                    const list: ProfileBasicResult[] = (res?.data?.result as ProfileBasicResult[]) ?? [];
                    setOptions(list.map(p => ({
                        id: p.id,
                        name: p.name ?? undefined,
                        email: p.email ?? undefined,
                        roles: p.roles as string[] | undefined,
                    })));
                })
                .catch(err => {
                    if (reqId !== requestIdRef.current) return;
                    logger.error('UserPicker', 'Search failed', err);
                    setOptions([]);
                })
                .finally(() => {
                    if (reqId === requestIdRef.current) setLoading(false);
                });
        }, debounceMs);
        return () => window.clearTimeout(handle);
    }, [open, inputValue, debounceMs]);

    // Filter out locked, excluded, and already-selected ids from the visible options.
    const selectedIds = React.useMemo(() => new Set(value.map(v => v.id)), [value]);
    const visibleOptions = React.useMemo(() => options.filter(o => {
        if (lockedSet.has(o.id)) return false;
        if (excludeSet.has(o.id)) return false;
        if (hideAlreadySelected && selectedIds.has(o.id)) return false;
        return true;
    }), [options, lockedSet, excludeSet, hideAlreadySelected, selectedIds]);

    const labelOf = (o: UserPickerOption) => o.name?.trim() || o.email || o.id;
    const initialOf = (o: UserPickerOption) =>
        (o.name?.trim()?.[0] ?? o.id[0] ?? '?').toUpperCase();

    return (
        <Stack spacing={1}>
            {lockedEntries.length > 0 && (
                <Stack direction="row" spacing={0.5} useFlexGap sx={{ flexWrap: 'wrap' }}>
                    {lockedEntries.map(o => (
                        <Chip
                            key={o.id}
                            size="small"
                            icon={<LockIcon sx={{ fontSize: 14 }} />}
                            label={labelOf(o)}
                            sx={{ bgcolor: 'action.disabledBackground', color: 'text.primary' }}
                        />
                    ))}
                </Stack>
            )}

            <Autocomplete<UserPickerOption, true>
                multiple
                open={open}
                onOpen={() => setOpen(true)}
                onClose={() => setOpen(false)}
                disabled={disabled}
                value={editableEntries}
                options={visibleOptions}
                filterOptions={(opts) => opts /* server-side filtering */}
                isOptionEqualToValue={(opt, val) => opt.id === val.id}
                getOptionLabel={labelOf}
                loading={loading}
                inputValue={inputValue}
                onInputChange={(_e, v, reason) => {
                    // Reset input after a chip is added so users can search again immediately.
                    if (reason === 'reset') setInputValue('');
                    else setInputValue(v);
                }}
                onChange={(_e, next) => {
                    // Re-attach locked entries (kept out of the Autocomplete value internally).
                    onChange([...lockedEntries, ...next]);
                }}
                renderOption={(props, option) => {
                    const { key: _key, ...rest } = props as React.HTMLAttributes<HTMLLIElement> & { key?: React.Key };
                    return (
                        <Box component="li" key={option.id} {...rest} sx={{ py: 0.75, display: 'flex', alignItems: 'center' }}>
                            <Avatar sx={{ width: 28, height: 28, fontSize: '0.85rem', mr: 1.25 }}>
                                {initialOf(option)}
                            </Avatar>
                            <Box sx={{ flexGrow: 1, minWidth: 0 }}>
                                <Typography variant="body2" sx={{ fontWeight: 500 }} noWrap>
                                    {labelOf(option)}
                                </Typography>
                                <Typography variant="caption" color="text.secondary" noWrap>
                                    {option.email ? `${option.email} · ` : ''}{option.id}
                                </Typography>
                            </Box>
                            {option.roles && option.roles.length > 0 && (
                                <Chip
                                    size="small"
                                    label={option.roles[0]}
                                    sx={{ ml: 1, height: 20, fontSize: '0.7rem' }}
                                />
                            )}
                        </Box>
                    );
                }}
                renderInput={(params) => {
                    const paramSlotProps = params.slotProps ?? {};
                    const inputSlot = (paramSlotProps as { input?: { endAdornment?: React.ReactNode } }).input ?? {};
                    return (
                        <TextField
                            {...params}
                            label={label}
                            placeholder={editableEntries.length === 0 && lockedEntries.length === 0 ? placeholder : undefined}
                            helperText={helperText}
                            error={error}
                            required={required && value.length === 0}
                            slotProps={{
                                ...paramSlotProps,
                                input: {
                                    ...inputSlot,
                                    endAdornment: (
                                        <>
                                            {loading ? <CircularProgress color="inherit" size={18} /> : null}
                                            {inputSlot.endAdornment}
                                        </>
                                    ),
                                },
                            }}
                        />
                    );
                }}
                noOptionsText={inputValue.trim()
                    ? 'No matching elevated users'
                    : 'Type a name or email to search'}
            />
        </Stack>
    );
};
